import { useState, useEffect } from "react";
import NavbarGestionSalas from "../components/NavbarGestionSalas";
import "../styles/GestionarSalas.css";

function GestionarSalas({ user }) {
  const [salas, setSalas] = useState([]);
  const [showModal, setShowModal] = useState(false);

  const [sala, setSala] = useState({
    id: "",
    nombre: "",
    ubicacion: "",
    capacidad: "",
    estado: "disponible"
  });

  const obtenerSalas = async () => {
    try {
      const response = await fetch("http://localhost:3001/api/salas", {
        credentials: "include",
      });
      const data = await response.json();
      setSalas(data);
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    obtenerSalas();
  }, []);

  const crearSala = async () => {
    if (!sala.id || !sala.nombre || !sala.ubicacion || !sala.capacidad) {
      alert("Todos los campos son obligatorios");
      return;
    }

    try {
      const response = await fetch("http://localhost:3001/api/salas", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...sala,
          capacidad: Number(sala.capacidad),
          estado: sala.estado.toLowerCase()
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        alert(JSON.stringify(data));
        return;
      }

      alert("Sala creada ✅");
      setShowModal(false);
      obtenerSalas();

      setSala({
        id: "",
        nombre: "",
        ubicacion: "",
        capacidad: "",
        estado: "disponible"
      });

    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div className="container">
      <NavbarGestionSalas userRole={user?.rol || ""} />

      {/* HEADER */}
      <div className="header">
        <h2>Gestión de Salas</h2>
        <button className="btn-crear" onClick={() => setShowModal(true)}>
          + Crear Sala
        </button>
      </div>

      {/* GRID */}
      <div className="grid-salas">
        {salas.map((sala) => (
          <div key={sala.id} className="card">
            <div className="card-content">
              <h3>{sala.nombre}</h3>
              <p>{sala.ubicacion}</p>

              <div className="card-info">
                <span>👥 {sala.capacidad}</span>
                <span className={`estado ${sala.estado}`}>
                  {sala.estado}
                </span>
              </div>
            </div>

            <div className="overlay">
              <button>Ver Info</button>
              <button>Recursos</button>
              <button className="editar">Editar</button>
            </div>
          </div>
        ))}
      </div>

      {/* MODAL */}
      {showModal && (
        <div className="modal-overlay">
          <div className="modal">

            <h3>Crear Sala</h3>

            <input
              placeholder="Código Sala"
              value={sala.id}
              onChange={(e) => setSala({ ...sala, id: e.target.value })}
            />

            <input
              placeholder="Nombre"
              value={sala.nombre}
              onChange={(e) => setSala({ ...sala, nombre: e.target.value })}
            />

            <input
              placeholder="Ubicación"
              value={sala.ubicacion}
              onChange={(e) => setSala({ ...sala, ubicacion: e.target.value })}
            />

            <input
              placeholder="Capacidad"
              type="number"
              value={sala.capacidad}
              onChange={(e) => setSala({ ...sala, capacidad: e.target.value })}
            />

            <select
              value={sala.estado}
              onChange={(e) => setSala({ ...sala, estado: e.target.value })}
            >
              <option value="disponible">Disponible</option>
              <option value="ocupada">Ocupada</option>
            </select>

            <div className="modal-buttons">
              <button className="cancelar" onClick={() => setShowModal(false)}>
                Cancelar
              </button>
              <button className="crear" onClick={crearSala}>
                Crear
              </button>
            </div>

          </div>
        </div>
      )}

      {/* FOOTER */}
      <footer className="footer">
        <p>Sistema de Gestión de Salas © 2026</p>
      </footer>
    </div>
  );
}

export default GestionarSalas;
